import{_ as i,o as h,c as t,a0 as c}from"./chunks/framework.jwovEGr5.js";const d=JSON.parse('{"title":"In ấn","description":"","frontmatter":{"title":"In ấn"},"headers":[],"relativePath":"printing.md","filePath":"printing.md"}'),a={name:"printing.md"};function o(g,n,r,u,e,l){return h(),t("div",null,[...n[0]||(n[0]=[c('<h1 id="in-an" tabindex="-1">In ấn <a class="header-anchor" href="#in-an" aria-label="Permalink to &quot;In ấn&quot;">​</a></h1><p>Mô-đun <strong>In ấn (Printing)</strong> trong ABNERP cung cấp công cụ tùy chỉnh toàn diện cho việc in ấn chứng từ, hóa đơn, báo cáo và các tài liệu kinh doanh. Hệ thống cho phép tạo bố cục in chuyên nghiệp với thương hiệu riêng của doanh nghiệp.</p><h2 id="đinh-dang-in" tabindex="-1">Định dạng in <a class="header-anchor" href="#đinh-dang-in" aria-label="Permalink to &quot;Định dạng in&quot;">​</a></h2><p><strong>Định dạng in (Print Format)</strong> là bố cục hiển thị của một loại chứng từ khi in hoặc xuất PDF. ABNERP cung cấp sẵn các định dạng in cho tất cả chứng từ mặc định (hóa đơn bán hàng, đơn mua hàng, báo giá, phiếu nhập kho, v.v.). Người dùng có thể tùy chỉnh các định dạng này bằng cách:</p><ul><li>Thay đổi thứ tự và vị trí các trường thông tin</li><li>Thêm logo và thông tin công ty</li><li>Tùy chỉnh màu sắc, phông chữ, kích thước</li><li>Ẩn/hiện các trường không cần thiết</li></ul><h2 id="kieu-in" tabindex="-1">Kiểu in <a class="header-anchor" href="#kieu-in" aria-label="Permalink to &quot;Kiểu in&quot;">​</a></h2><p><strong>Kiểu in (Print Style)</strong> xác định giao diện tổng thể cho tài liệu in. ABNERP có sẵn các kiểu in như:</p><ul><li><strong>Classic</strong>: giao diện truyền thống, trang trọng</li><li><strong>Modern</strong>: thiết kế hiện đại, thoáng</li><li><strong>Standard</strong>: tiêu chuẩn, phù hợp đa mục đích</li></ul><p>Người dùng cũng có thể tạo kiểu in tùy chỉnh thông qua CSS để kiểm soát hoàn toàn giao diện.</p><h2 id="tieu-đe-in" tabindex="-1">Tiêu đề in <a class="header-anchor" href="#tieu-đe-in" aria-label="Permalink to &quot;Tiêu đề in&quot;">​</a></h2><p><strong>Tiêu đề in (Letter Head)</strong> cho phép xác định nội dung phần đầu và phần cuối của tài liệu in. Bạn có thể tạo nhiều tiêu đề in khác nhau cho các mục đích riêng biệt: hóa đơn, báo giá, hợp đồng, biên bản, v.v. Mỗi tiêu đề in có thể bao gồm logo, tên công ty, địa chỉ, mã số thuế và đường kẻ phân cách.</p><h2 id="mau-đia-chi" tabindex="-1">Mẫu địa chỉ <a class="header-anchor" href="#mau-đia-chi" aria-label="Permalink to &quot;Mẫu địa chỉ&quot;">​</a></h2><p><strong>Mẫu địa chỉ (Address Template)</strong> định dạng cách hiển thị địa chỉ trên các chứng từ in. Mỗi quốc gia có thể có mẫu địa chỉ riêng phù hợp với chuẩn địa phương. Người dùng có thể tạo mẫu địa chỉ tùy chỉnh bằng Jinja template, bao gồm các trường như quốc gia, thành phố, quận/huyện, đường phố và mã bưu điện.</p><h2 id="đieu-khoan-va-đieu-kien" tabindex="-1">Điều khoản và điều kiện <a class="header-anchor" href="#đieu-khoan-va-đieu-kien" aria-label="Permalink to &quot;Điều khoản và điều kiện&quot;">​</a></h2><p><strong>Điều khoản và điều kiện (Terms and Conditions)</strong> cho phép lưu trữ các điều khoản sử dụng phổ biến và tự động chèn vào chứng từ. Có thể tạo nhiều bộ điều khoản khác nhau (bán hàng với khách lẻ, bán buôn, mua hàng, hợp đồng dịch vụ) và gắn với từng loại chứng từ hoặc từng khách hàng cụ thể. Hỗ trợ viết nội dung dạng văn bản phong phú với định dạng HTML.</p><p>Tất cả các tùy chỉnh in ấn đều có thể xem trước (preview) trực tiếp trên giao diện trước khi sử dụng, đảm bảo kết quả in ra đúng như mong muốn.</p>',16)])])}const s=i(a,[["render",o]]);export{d as __pageData,s as default};
